// ─── DONUT CHART ──────────────────────────────────────────────────────────────
function DonutChart({ slices, T }) {
  const SIZE = 280, cx = 140, cy = 140, outerR = 118, innerR = 70;
  const total = slices.reduce((s, d) => s + d.value, 0);
  if (!total) return null;
  const GAP = 0.025;
  let angle = -Math.PI / 2;

  // Pre-compute slice geometry
  const computed = slices.map((seg) => {
    const sweep  = (seg.value / total) * 2 * Math.PI;
    const startA = angle + GAP / 2;
    const endA   = startA + sweep - GAP;
    angle += sweep;
    const midA  = (startA + endA) / 2;
    const cos1  = Math.cos(startA), sin1 = Math.sin(startA);
    const cos2  = Math.cos(endA),   sin2 = Math.sin(endA);
    const large = (sweep - GAP) > Math.PI ? 1 : 0;
    const path  = [
      `M ${(cx + outerR*cos1).toFixed(1)} ${(cy + outerR*sin1).toFixed(1)}`,
      `A ${outerR} ${outerR} 0 ${large} 1 ${(cx + outerR*cos2).toFixed(1)} ${(cy + outerR*sin2).toFixed(1)}`,
      `L ${(cx + innerR*cos2).toFixed(1)} ${(cy + innerR*sin2).toFixed(1)}`,
      `A ${innerR} ${innerR} 0 ${large} 0 ${(cx + innerR*cos1).toFixed(1)} ${(cy + innerR*sin1).toFixed(1)}`,
      `Z`,
    ].join(" ");
    const pct    = ((seg.value / total) * 100).toFixed(1);
    const labelR = (outerR + innerR) / 2;
    const lx     = (cx + labelR * Math.cos(midA)).toFixed(1);
    const ly     = (cy + labelR * Math.sin(midA)).toFixed(1);
    // Outer label line coords
    const lineR1 = outerR + 6;
    const lineR2 = outerR + 22;
    const lx1 = (cx + lineR1 * Math.cos(midA)).toFixed(1);
    const ly1 = (cy + lineR1 * Math.sin(midA)).toFixed(1);
    const lx2 = (cx + lineR2 * Math.cos(midA)).toFixed(1);
    const ly2 = (cy + lineR2 * Math.sin(midA)).toFixed(1);
    const labelAnchor = Math.cos(midA) >= 0 ? "start" : "end";
    const lx3 = (cx + (lineR2 + (Math.cos(midA) >= 0 ? 4 : -4)) * Math.cos(midA)).toFixed(1);
    return { ...seg, path, pct, lx, ly, lx1, ly1, lx2, ly2, lx3, labelAnchor, midA };
  });

  return (
    <svg width={SIZE} height={SIZE} viewBox={`0 0 ${SIZE} ${SIZE}`} style={{ overflow:"visible" }}>
      {/* Slices */}
      {computed.map(s => (
        <path key={s.name} d={s.path} fill={s.color} opacity={0.9}/>
      ))}

      {/* Inner ring % labels */}
      {computed.map(s => (
        <g key={s.name + "_lbl"}>
          <text x={s.lx} y={parseFloat(s.ly) - 6} textAnchor="middle"
            fill="#fff" fontSize={14} fontWeight={800}
            fontFamily="Inter,sans-serif" style={{ pointerEvents:"none" }}>
            {s.pct}%
          </text>
          <text x={s.lx} y={parseFloat(s.ly) + 11} textAnchor="middle"
            fill="rgba(255,255,255,0.75)" fontSize={10} fontWeight={500}
            fontFamily="Inter,sans-serif" style={{ pointerEvents:"none" }}>
            {s.name}
          </text>
        </g>
      ))}

      {/* Centre */}
      <text x={cx} y={cy - 12} textAnchor="middle" fill={T.text}
        fontSize={20} fontWeight={700} fontFamily="DM Serif Display,serif">
        {fmtM(total)}
      </text>
      <text x={cx} y={cy + 8} textAnchor="middle" fill={T.muted}
        fontSize={10} fontFamily="Inter,sans-serif" letterSpacing="1.5">
        TOTAL BAC
      </text>
    </svg>
  );
}

// ─── BREAKDOWN SECTION ────────────────────────────────────────────────────────
const ORG_COLORS  = { Riphah:"#D89840", Trust:"#2DD4BF" };
const SEG_COLORS  = { Academic:"#60A5FA", Healthcare:"#34D399", Management:"#A78BFA", Investment:"#FB923C" };
const STRAT_PAL   = ["#60A5FA","#A78BFA","#FB923C","#34D399","#F472B6","#2DD4BF","#FBBF24","#F87171","#818CF8","#6EE7B7"];

function BreakdownBar({ label, count, actual, planned, released, color, T, editing, editVal, onEditChange }) {
  const plannedAbs = (planned || 0) * 1e6;
  const maxVal     = Math.max(actual, plannedAbs > 0 ? plannedAbs : actual) * 1.08 || 1;
  const actualW    = Math.min(100, (actual / maxVal) * 100);
  const plannedW   = plannedAbs > 0 ? Math.min(100, (plannedAbs / maxVal) * 100) : 0;
  const relW       = Math.min(100, (released / maxVal) * 100);
  const isOver     = plannedAbs > 0 && actual > plannedAbs;
  const pct        = plannedAbs > 0 ? ((actual / plannedAbs) * 100).toFixed(1) : null;
  const relPct     = actual > 0 ? ((released / actual) * 100).toFixed(1) : "0.0";

  return (
    <div style={{ marginBottom: 18 }}>
      <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:6, gap:8, flexWrap:"wrap" }}>
        <div style={{ display:"flex", alignItems:"center", gap:8 }}>
          <div style={{ width:9, height:9, borderRadius:"50%", background:color, flexShrink:0 }}/>
          <span style={{ fontSize:13, fontWeight:600, color:T.text }}>{label}</span>
          <span style={{ fontSize:11, color:T.dim }}>{count} projects</span>
          {isOver && <span style={{ fontSize:9, fontWeight:700, background:"rgba(248,113,113,0.12)", color:"#F87171", padding:"2px 8px", borderRadius:20 }}>OVER TARGET</span>}
        </div>
        <div style={{ display:"flex", alignItems:"center", gap:12, fontSize:12, fontVariantNumeric:"tabular-nums" }}>
          <span style={{ color, fontWeight:600 }}>{fmtM(actual)}</span>
          {plannedAbs > 0 && !editing && <span style={{ color:T.dim }}>of {fmtM(plannedAbs)} planned ({pct}%)</span>}
          <span style={{ color:"#2DD4BF", fontSize:11 }}>↓ {fmtM(released)} released</span>
          {editing && (
            <div style={{ display:"flex", alignItems:"center", gap:5 }}>
              <span style={{ fontSize:11, color:T.muted }}>Target (M):</span>
              <input type="number" step="0.1" value={editVal} onChange={e=>onEditChange(e.target.value)}
                placeholder="e.g. 600"
                style={{ width:90, background:T.inputBg, border:`1px solid ${color}`, borderRadius:6, padding:"3px 8px", fontSize:12, color:T.text, fontFamily:"Inter,sans-serif", outline:"none" }}/>
            </div>
          )}
        </div>
      </div>
      {/* Bar stack */}
      <div style={{ position:"relative", height:22 }}>
        {/* Planned ghost bar */}
        {plannedW > 0 && <div style={{ position:"absolute", left:0, top:5, height:12, width:plannedW+"%", background:`${color}16`, borderRadius:6, border:`1px dashed ${color}45` }}/>}
        {/* Actual bar */}
        <div style={{ position:"absolute", left:0, top:5, height:12, width:actualW+"%", background:isOver?"#F87171":color, borderRadius:6, opacity:0.82, transition:"width .5s" }}/>
        {/* Released thin bar overlay */}
        <div style={{ position:"absolute", left:0, top:10, height:4, width:relW+"%", background:"#2DD4BF", borderRadius:2, opacity:0.9 }}/>
        {/* Planned tick */}
        {plannedW > 0 && <div style={{ position:"absolute", left:plannedW+"%", top:3, height:16, width:2, background:color, borderRadius:1, opacity:0.65 }}/>}
      </div>
      <div style={{ display:"flex", gap:14, marginTop:3, fontSize:10, color:T.dim }}>
        <span style={{ display:"flex", alignItems:"center", gap:4 }}><span style={{ width:8, height:4, background:color, borderRadius:2, display:"inline-block", opacity:.7 }}/> Actual BAC</span>
        <span style={{ display:"flex", alignItems:"center", gap:4 }}><span style={{ width:8, height:4, background:"#2DD4BF", borderRadius:2, display:"inline-block" }}/> Released ({relPct}%)</span>
        {plannedW > 0 && <span style={{ display:"flex", alignItems:"center", gap:4 }}><span style={{ width:2, height:8, background:color, borderRadius:1, display:"inline-block", opacity:.65 }}/> Planned target</span>}
        {isOver && <span style={{ color:"#F87171" }}>Over by {fmtM(actual - plannedAbs)}</span>}
        {!isOver && plannedAbs > 0 && <span>Gap: {fmtM(plannedAbs - actual)}</span>}
      </div>
    </div>
  );
}

function BreakdownSection({ T, session }) {
  const [projects, setProjects] = useState([]);
  const [targets,  setTargets]  = useState({});
  const [fy,       setFy]       = useState("__all__");
  const [allFYs,   setAllFYs]   = useState([]);
  const [editing,  setEditing]  = useState(false);
  const [editBuf,  setEditBuf]  = useState({});
  const [saving,   setSaving]   = useState(false);
  const [loading,  setLoading]  = useState(true);
  const isPMO = session?.role === "pmo";

  useEffect(() => {
    (async () => {
      try {
        const [proj, sett] = await Promise.all([
          supa("/rest/v1/projects?select=id,bac,amount_released,payments_made,fiscal_year,segments(name),sectors(name),strategic_priority", {}, session.access_token),
          supa("/rest/v1/settings?key=eq.dashboard_breakdowns&select=value", {}, session.access_token),
        ]);
        setProjects(proj);
        setTargets(sett[0]?.value || {});
        const fys = [...new Set(proj.map(p=>p.fiscal_year).filter(Boolean))].sort();
        setAllFYs(fys);
      } catch(_) {}
      setLoading(false);
    })();
  }, [session.access_token]);

  const fyProjects = fy === "__all__" ? projects : projects.filter(p => p.fiscal_year === fy);

  // Aggregate
  const agg = (key) => {
    const m = {};
    fyProjects.forEach(p => {
      const k = key(p) || "Unclassified";
      if (!m[k]) m[k] = { bac:0, released:0, count:0 };
      m[k].bac      += parseFloat(p.bac) || 0;
      m[k].released += parseFloat(p.amount_released) || 0;
      m[k].count    += 1;
    });
    return m;
  };

  const byOrg   = agg(p => p.segments?.name);
  const bySeg   = agg(p => p.sectors?.name);
  const byStrat = agg(p => p.strategic_priority || null);
  delete byStrat["Unclassified"]; // don't show null strategic priorities

  const fyKey    = fy === "__all__" ? "__all__" : fy;
  const fyTgts   = targets[fyKey] || {};
  const orgTgts  = fyTgts.orgs  || {};
  const segTgts  = fyTgts.segments || {};
  const stratTgts = fyTgts.strategic_priorities || {};

  const startEdit = () => {
    setEditBuf({
      orgs:  Object.fromEntries(Object.keys(byOrg).map(k  => [k, orgTgts[k]?.bac   || ""])),
      segs:  Object.fromEntries(Object.keys(bySeg).map(k  => [k, segTgts[k]?.bac   || ""])),
      strat: Object.fromEntries(Object.keys(byStrat).map(k => [k, stratTgts[k]?.bac || ""])),
    });
    setEditing(true);
  };

  const saveTargets = async () => {
    setSaving(true);
    const parse = (buf) => Object.fromEntries(Object.entries(buf).map(([k,v])=>[k,{bac:parseFloat(v)||0}]));
    const updated = { ...targets, [fyKey]: { orgs:parse(editBuf.orgs||{}), segments:parse(editBuf.segs||{}), strategic_priorities:parse(editBuf.strat||{}) } };
    await supa("/rest/v1/settings", {
      method:"POST",
      body:JSON.stringify({ key:"dashboard_breakdowns", value:updated }),
      headers:{"Prefer":"resolution=merge-duplicates,return=minimal"}
    }, session.access_token);
    setTargets(updated); setEditing(false); setSaving(false);
  };

  if (loading) return null;

  const SectionCard = ({ title, children, note }) => (
    <div style={{ background:T.card, border:`1px solid ${T.border}`, borderRadius:12, padding:"18px 22px" }}>
      <div style={{ fontSize:11, fontWeight:700, color:T.muted, textTransform:"uppercase", letterSpacing:2, marginBottom:note?4:16 }}>{title}</div>
      {note && <div style={{ fontSize:11, color:T.dim, marginBottom:14 }}>{note}</div>}
      {children}
    </div>
  );

  return (
    <div style={{ display:"flex", flexDirection:"column", gap:16 }}>
      {/* Header */}
      <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", padding:"4px 0" }}>
        <div style={{ fontSize:11, fontWeight:700, color:T.text, textTransform:"uppercase", letterSpacing:2, opacity:0.75 }}>Portfolio Breakdown · Planned vs Actual</div>
        <div style={{ display:"flex", gap:8, alignItems:"center" }}>
          <select value={fy} onChange={e=>setFy(e.target.value)}
            style={{ background:T.inputBg, border:`1px solid ${T.inputBorder}`, borderRadius:6, padding:"5px 10px", fontSize:12, color:T.text, fontFamily:"Inter,sans-serif", outline:"none" }}>
            <option value="__all__">All Fiscal Years</option>
            {allFYs.map(f=><option key={f} value={f}>{f}</option>)}
          </select>
          {isPMO && !editing && (
            <button onClick={startEdit}
              style={{ padding:"5px 13px", background:"none", border:`1px solid ${T.border}`, borderRadius:6, color:T.muted, fontSize:12, cursor:"pointer", fontFamily:"Inter,sans-serif", display:"flex", alignItems:"center", gap:6 }}>
              <Edit2 size={11}/> Set Targets
            </button>
          )}
          {isPMO && editing && (
            <div style={{ display:"flex", gap:7 }}>
              <button onClick={saveTargets} disabled={saving}
                style={{ padding:"5px 14px", background:NAVY, border:"none", borderRadius:6, color:"#fff", fontSize:12, fontWeight:700, cursor:"pointer", fontFamily:"Inter,sans-serif" }}>
                {saving?"Saving…":"Save Targets"}
              </button>
              <button onClick={()=>setEditing(false)}
                style={{ padding:"5px 10px", background:"none", border:`1px solid ${T.border}`, borderRadius:6, color:T.muted, fontSize:12, cursor:"pointer" }}>
                Cancel
              </button>
            </div>
          )}
        </div>
      </div>

      {/* ── Organisation split ── */}
      <div style={{ display:"flex", gap:14 }}>
        {Object.entries(byOrg).sort(([,a],[,b])=>b.bac-a.bac).map(([name, data]) => {
          const color      = ORG_COLORS[name] || "#60A5FA";
          const plannedAbs = (orgTgts[name]?.bac || 0) * 1e6;
          const isOver     = plannedAbs > 0 && data.bac > plannedAbs;
          const pct        = plannedAbs > 0 ? Math.min(100,(data.bac/plannedAbs)*100) : 0;
          const relPct     = data.bac > 0 ? (data.released/data.bac)*100 : 0;

          return (
            <div key={name} style={{ flex:1, background:T.card, border:`1px solid ${T.border}`, borderRadius:12, padding:"18px 20px", borderTop:`3px solid ${color}`, display:"flex", flexDirection:"column", gap:12 }}>
              <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start" }}>
                <div>
                  <div style={{ fontSize:15, fontWeight:700, color:T.text }}>{name}</div>
                  <div style={{ fontSize:11, color:T.dim }}>{data.count} projects · {fy === "__all__" ? "All FY" : fy}</div>
                </div>
                {isOver && <span style={{ fontSize:9, fontWeight:700, background:"rgba(248,113,113,0.12)", color:"#F87171", padding:"3px 9px", borderRadius:20 }}>OVER TARGET</span>}
              </div>

              <div style={{ display:"flex", alignItems:"baseline", gap:10 }}>
                <div style={{ fontSize:30, fontWeight:700, color, fontFamily:"DM Serif Display,serif" }}>{fmtM(data.bac)}</div>
                {plannedAbs > 0 && !editing && <div style={{ fontSize:13, color:T.dim }}>/ {fmtM(plannedAbs)} planned</div>}
              </div>

              {plannedAbs > 0 && !editing && (
                <div>
                  <div style={{ display:"flex", justifyContent:"space-between", fontSize:11, color:T.dim, marginBottom:4 }}>
                    <span>{pct.toFixed(1)}% of target</span>
                    <span style={{ color:isOver?"#F87171":T.dim }}>{isOver?`+${fmtM(data.bac-plannedAbs)} over`:`${fmtM(plannedAbs-data.bac)} to go`}</span>
                  </div>
                  <div style={{ height:6, background:T.border, borderRadius:3, overflow:"hidden" }}>
                    <div style={{ width:pct+"%", height:"100%", background:isOver?"#F87171":color, borderRadius:3, transition:"width .5s" }}/>
                  </div>
                </div>
              )}

              <div>
                <div style={{ display:"flex", justifyContent:"space-between", fontSize:11, color:T.muted, marginBottom:4 }}>
                  <span>Amount Released</span><span style={{ color:"#2DD4BF" }}>{fmtM(data.released)} ({relPct.toFixed(1)}%)</span>
                </div>
                <div style={{ height:4, background:T.border, borderRadius:2 }}>
                  <div style={{ width:Math.min(100,relPct)+"%", height:"100%", background:"#2DD4BF", borderRadius:2 }}/>
                </div>
              </div>

              {editing && isPMO && (
                <div style={{ paddingTop:12, borderTop:`1px solid ${T.border}` }}>
                  <label style={{ fontSize:10, fontWeight:700, color:T.muted, textTransform:"uppercase", letterSpacing:1, display:"block", marginBottom:6 }}>Planned Budget (M)</label>
                  <input type="number" step="0.1"
                    value={editBuf.orgs?.[name] || ""}
                    onChange={e=>setEditBuf(b=>({...b,orgs:{...b.orgs,[name]:e.target.value}}))}
                    placeholder={`e.g. ${Math.round(data.bac/1e6/10)*10+50}`}
                    style={{ width:"100%", boxSizing:"border-box", background:T.inputBg, border:`1px solid ${color}`, borderRadius:7, padding:"8px 10px", fontSize:13, color:T.text, fontFamily:"Inter,sans-serif", outline:"none" }}/>
                  <div style={{ fontSize:10, color:T.dim, marginTop:4 }}>Enter in PKR Millions — e.g. 600 means PKR 600M</div>
                </div>
              )}
            </div>
          );
        })}
      </div>

      {/* ── Segment breakdown — donut chart ── */}
      <SectionCard title="By Segment">
        <div style={{ display:"flex", gap:32, alignItems:"center" }}>
          {/* Donut — 280px */}
          <div style={{ flexShrink:0, display:"flex", alignItems:"center", justifyContent:"center" }}>
            <DonutChart T={T}
              slices={Object.entries(bySeg).sort(([,a],[,b])=>b.bac-a.bac).map(([name, data])=>({
                name, value:data.bac, color:SEG_COLORS[name]||"#60A5FA"
              }))}/>
          </div>

          {/* Legend — 2 columns on wide, 1 on narrow */}
          <div style={{ flex:1, display:"grid", gridTemplateColumns:"1fr 1fr", gap:"16px 32px" }}>
            {(() => {
              const total = Object.values(bySeg).reduce((s,d)=>s+d.bac,0)||1;
              return Object.entries(bySeg).sort(([,a],[,b])=>b.bac-a.bac).map(([name, data]) => {
                const color      = SEG_COLORS[name]||"#60A5FA";
                const pct        = ((data.bac/total)*100).toFixed(1);
                const plannedAbs = (segTgts[name]?.bac||0)*1e6;
                const isOver     = plannedAbs>0 && data.bac>plannedAbs;
                const relPct     = data.bac>0 ? ((data.released/data.bac)*100).toFixed(1) : "0";
                return (
                  <div key={name} style={{ background:T.mainBg+"80", borderRadius:10, padding:"14px 16px", border:`1px solid ${color}30` }}>
                    {/* Header row */}
                    <div style={{ display:"flex", alignItems:"center", gap:8, marginBottom:10 }}>
                      <div style={{ width:12, height:12, borderRadius:3, background:color }}/>
                      <span style={{ fontSize:14, fontWeight:700, color:T.text }}>{name}</span>
                      <span style={{ fontSize:11, color:T.dim, marginLeft:"auto" }}>{data.count} projects</span>
                    </div>

                    {/* Big BAC number */}
                    <div style={{ display:"flex", alignItems:"baseline", gap:8, marginBottom:6 }}>
                      <span style={{ fontSize:24, fontWeight:700, color, fontFamily:"DM Serif Display,serif" }}>{fmtM(data.bac)}</span>
                      <span style={{ fontSize:14, color:T.muted, fontWeight:600 }}>{pct}%</span>
                    </div>

                    {/* Planned row */}
                    {plannedAbs>0 && !editing && (
                      <div style={{ fontSize:12, color:isOver?"#F87171":T.muted, marginBottom:8 }}>
                        {isOver ? "⚠ " : ""}Target: {fmtM(plannedAbs)}
                        {isOver && <span style={{ fontSize:10, fontWeight:700, color:"#F87171", background:"rgba(248,113,113,0.12)", padding:"1px 6px", borderRadius:20, marginLeft:6 }}>OVER</span>}
                      </div>
                    )}

                    {/* Edit input */}
                    {editing && (
                      <div style={{ display:"flex", alignItems:"center", gap:6, marginBottom:8 }}>
                        <span style={{ fontSize:11, color:T.muted }}>Target (M):</span>
                        <input type="number" step="0.1"
                          value={editBuf.segs?.[name]||""}
                          onChange={e=>setEditBuf(b=>({...b,segs:{...b.segs,[name]:e.target.value}}))}
                          placeholder="e.g. 320"
                          style={{ flex:1, background:T.inputBg, border:`1px solid ${color}`, borderRadius:6, padding:"4px 8px", fontSize:12, color:T.text, fontFamily:"Inter,sans-serif", outline:"none" }}/>
                      </div>
                    )}

                    {/* Released bar */}
                    <div style={{ height:6, background:T.border, borderRadius:3 }}>
                      <div style={{ width:Math.min(100,parseFloat(relPct))+"%" , height:"100%", background:"#2DD4BF", borderRadius:3 }}/>
                    </div>
                    <div style={{ display:"flex", justifyContent:"space-between", marginTop:5, fontSize:11 }}>
                      <span style={{ color:T.muted }}>Released</span>
                      <span style={{ color:"#2DD4BF", fontWeight:600 }}>{fmtM(data.released)} ({relPct}%)</span>
                    </div>
                  </div>
                );
              });
            })()}
          </div>
        </div>
      </SectionCard>

      {/* ── Strategic Priority breakdown ── */}
      <SectionCard title="By Strategic Priority"
        note={Object.keys(byStrat).length===0 ? "No strategic priorities in current data — import Excel with the 'Strategic Priority' column filled in to populate this section." : null}>
        {Object.entries(byStrat).sort(([,a],[,b])=>b.bac-a.bac).map(([name, data], idx) => (
          <BreakdownBar key={name} label={name} count={data.count}
            actual={data.bac} planned={stratTgts[name]?.bac || 0} released={data.released}
            color={STRAT_PAL[idx % STRAT_PAL.length]} T={T} editing={editing}
            editVal={editBuf.strat?.[name]||""}
            onEditChange={v=>setEditBuf(b=>({...b,strat:{...b.strat,[name]:v}}))}/>
        ))}
      </SectionCard>
    </div>
  );
}

// ─── DASHBOARD PROJECT LIST ───────────────────────────────────────────────────
const STAGE_LABEL = { pdd_not_submitted:"PDD Not Submitted", identified:"PDD Submitted", df_review:"DF Review", ed_review:"ED Review", mt_review:"MT Review", approved:"Approved", closed:"Closed" };

function DashProjectList({ T, projects, tab, activeCard, onSelectProject }) {
  if (!projects || projects.length === 0) {
    return (
      <div style={{ background:T.card, border:"1px solid "+T.border, borderRadius:12, padding:"32px 24px", textAlign:"center", color:T.dim, fontSize:13 }}>
        No projects match this filter.
      </div>
    );
  }

  const cardLabels = {
    pipeline: { pdd_not_submitted:"PDD Not Submitted", pdds_submitted:"PDD Submitted", in_df:"DF Review", in_ed:"ED Review", in_mt:"MT Review", approved:"Approved" },
    execution: { active_projects:"Active Projects", on_schedule:"On Schedule", delayed:"Delayed", over_budget:"Over Budget", scope_change:"Change in Scope", closed:"Closed" },
  };
  const filterLabel = activeCard ? (cardLabels[tab]?.[activeCard] || "All") : "All";

  const th = { padding:"9px 12px", fontSize:10, fontWeight:700, color:T.text, textTransform:"uppercase", letterSpacing:1.5, textAlign:"left", borderBottom:"1px solid "+T.border, whiteSpace:"nowrap", opacity:0.65 };
  const td = { padding:"11px 12px", fontSize:12.5, color:T.text, borderBottom:"1px solid "+T.border+"80", verticalAlign:"middle" };

  return (
    <div style={{ background:T.card, border:"1px solid "+T.border, borderRadius:12, overflow:"hidden" }}>
      {/* List header */}
      <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", padding:"14px 18px", borderBottom:"1px solid "+T.border }}>
        <div style={{ display:"flex", alignItems:"center", gap:10 }}>
          <div style={{ width:3, height:14, background:GOLD, borderRadius:2 }} />
          <span style={{ fontSize:12, fontWeight:700, color:T.text, textTransform:"uppercase", letterSpacing:1 }}>
            {tab === "pipeline" ? "PDD Status" : "Project Health"} — {filterLabel}
          </span>
          <span style={{ fontSize:11, color:T.dim, background:T.border, padding:"2px 8px", borderRadius:20 }}>
            {projects.length} {projects.length === 1 ? "project" : "projects"}
          </span>
        </div>
        <span style={{ fontSize:11, color:T.dim }}>Click a row to view details</span>
      </div>

      {/* Table */}
      <div style={{ overflowX:"auto" }}>
        <table style={{ width:"100%", borderCollapse:"collapse" }}>
          <thead>
            <tr style={{ background:T.mainBg+"80" }}>
              <th style={{ ...th, width:40 }}>#</th>
              <th style={th}>Project ID</th>
              <th style={{ ...th, minWidth:220 }}>Project Name</th>
              <th style={th}>Organization</th>
              <th style={th}>Segment</th>
              <th style={{ ...th, textAlign:"right" }}>BAC</th>
              <th style={th}>Stage</th>
              {tab === "execution" && <th style={th}>Schedule</th>}
              {tab === "execution" && <th style={th}>Budget</th>}
              <th style={th}>Priority</th>
            </tr>
          </thead>
          <tbody>
            {projects.map((p, i) => (
              <tr key={p.id}
                onClick={() => onSelectProject && onSelectProject(p.id)}
                style={{ cursor:"pointer", transition:"background .12s" }}
                onMouseEnter={e => e.currentTarget.style.background = T.border+"50"}
                onMouseLeave={e => e.currentTarget.style.background = "transparent"}>
                <td style={{ ...td, color:T.dim }}>{i+1}</td>
                <td style={{ ...td, fontFamily:"'JetBrains Mono',monospace", fontSize:11.5, color:T.muted, whiteSpace:"nowrap" }}>
                  {p.is_carry_forward && <span style={{ fontSize:8, fontWeight:700, background:"rgba(216,152,64,0.15)", color:GOLD, padding:"1px 4px", borderRadius:3, marginRight:5 }}>CF</span>}
                  {p.code}
                </td>
                <td style={{ ...td, maxWidth:260, overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap", fontWeight:500 }}>{p.name}</td>
                <td style={{ ...td, fontSize:12, color:T.muted }}>{p.segments?.name||"—"}</td>
                <td style={{ ...td, fontSize:12, color:T.muted }}>{p.sectors?.name||"—"}</td>
                <td style={{ ...td, textAlign:"right", fontVariantNumeric:"tabular-nums", color:GOLD, fontWeight:600 }}>{fmtM(p.bac)}</td>
                <td style={td}><StageBadge stage={p.workflow_stage}/></td>
                {tab === "execution" && (
                  <td style={td}>
                    {p.manual_schedule_flag === "on_time"  && <span style={{ fontSize:10, fontWeight:700, color:"#2DD4BF", background:"rgba(45,212,191,0.1)", padding:"2px 7px", borderRadius:20 }}>On Time</span>}
                    {p.manual_schedule_flag === "delayed"  && <span style={{ fontSize:10, fontWeight:700, color:"#F87171", background:"rgba(248,113,113,0.1)", padding:"2px 7px", borderRadius:20 }}>Delayed</span>}
                    {p.manual_schedule_flag === "not_started" && <span style={{ fontSize:10, color:T.dim }}>—</span>}
                    {!p.manual_schedule_flag && <span style={{ fontSize:10, color:T.dim }}>—</span>}
                  </td>
                )}
                {tab === "execution" && (
                  <td style={td}>
                    {p.manual_budget_flag === "within" && <span style={{ fontSize:10, fontWeight:700, color:"#2DD4BF", background:"rgba(45,212,191,0.1)", padding:"2px 7px", borderRadius:20 }}>Within</span>}
                    {p.manual_budget_flag === "over"   && <span style={{ fontSize:10, fontWeight:700, color:"#F87171", background:"rgba(248,113,113,0.1)", padding:"2px 7px", borderRadius:20 }}>Over</span>}
                    {p.manual_budget_flag === "not_started" && <span style={{ fontSize:10, color:T.dim }}>—</span>}
                    {!p.manual_budget_flag && <span style={{ fontSize:10, color:T.dim }}>—</span>}
                  </td>
                )}
                <td style={td}>
                  <span style={{ display:"inline-flex", alignItems:"center", gap:5 }}>
                    <span style={{ width:7, height:7, borderRadius:"50%", background:PRIORITY[p.priority]||"#aaa" }}/>
                    <span style={{ fontSize:11, color:T.muted }}>{PRIORITY_LABEL[p.priority]||"—"}</span>
                  </span>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

// ─── COMMAND CENTER ───────────────────────────────────────────────────────────
function CommandCenter({ T, session, onSelectProject }) {
  const [data,         setData]         = useState(null);
  const [loading,      setLoading]      = useState(true);
  const [err,          setErr]          = useState(null);
  const [kpiOverrides, setKpiOverrides] = useState({});
  const [activeTab,    setActiveTab]    = useState("pipeline");
  const [activeCard,   setActiveCard]   = useState(null);
  const [dashProjects, setDashProjects] = useState([]);

  const canEdit = session?.role === "pmo";

  const load = useCallback(async () => {
    setLoading(true); setErr(null);
    try {
      const [rows, settings, projs] = await Promise.all([
        supa("/rest/v1/portfolio_dashboard?select=*", {}, session.access_token),
        supa("/rest/v1/settings?key=eq.dashboard_kpis&select=value", {}, session.access_token),
        supa("/rest/v1/projects?select=id,code,name,bac,fiscal_year,workflow_stage,priority,manual_schedule_flag,manual_budget_flag,is_carry_forward,scope_change,segments(name),sectors(name)&order=code.asc", {}, session.access_token),
      ]);
      setData(rows[0]);
      setKpiOverrides(settings[0]?.value || {});
      setDashProjects(projs);
    } catch (e) { setErr(e.message); }
    setLoading(false);
  }, [session.access_token]);

  useEffect(() => { load(); }, [load]);

  const saveKPI = useCallback(async (key, { value, sub }) => {
    const updated = { ...kpiOverrides, [key]: { value, sub } };
    await supa("/rest/v1/settings", {
      method: "POST",
      body: JSON.stringify({ key: "dashboard_kpis", value: updated }),
      headers: { "Prefer": "resolution=merge-duplicates,return=minimal" },
    }, session.access_token);
    setKpiOverrides(updated);
  }, [kpiOverrides, session.access_token]);

  const kv = (key, calcValue, calcSub) => {
    const ov = kpiOverrides[key];
    return {
      value: (ov?.value != null && ov.value !== "") ? ov.value : calcValue,
      sub:   (ov?.sub   != null && ov.sub   !== "") ? ov.sub   : calcSub,
    };
  };

  const switchTab = (tab) => { setActiveTab(tab); setActiveCard(null); };
  const toggleCard = (cardId) => {
    setActiveCard(prev => prev === cardId ? null : cardId);
    // Scroll the page down so the project list is visible after a short delay
    setTimeout(() => {
      const el = document.getElementById("dash-project-list");
      if (el) el.scrollIntoView({ behavior:"smooth", block:"nearest" });
    }, 80);
  };

  // ── Filter projects for the list panel ────────────────────────────────────
  const filteredProjects = (() => {
    if (activeTab === "pipeline") {
      const stageMap = { pdd_not_submitted:"pdd_not_submitted", pdds_submitted:"identified", in_df:"df_review", in_ed:"ed_review", in_mt:"mt_review", approved:"approved" };
      return dashProjects.filter(p => p.workflow_stage === (stageMap[activeCard] || "__none__"));
    }
    if (activeTab === "execution") {
      if (activeCard === "active_projects") return dashProjects.filter(p => p.workflow_stage === "approved");
      if (activeCard === "on_schedule")    return dashProjects.filter(p => p.workflow_stage === "approved" && p.manual_schedule_flag === "on_time");
      if (activeCard === "delayed")        return dashProjects.filter(p => p.workflow_stage === "approved" && p.manual_schedule_flag === "delayed");
      if (activeCard === "over_budget")    return dashProjects.filter(p => p.workflow_stage === "approved" && p.manual_budget_flag === "over");
      if (activeCard === "scope_change")   return dashProjects.filter(p => p.scope_change === true);
      if (activeCard === "closed")         return dashProjects.filter(p => p.workflow_stage === "closed");
    }
    if (activeTab === "financials" && activeCard === "payments_pending") {
      return dashProjects.filter(p => p.payments_pending);
    }
    if (activeTab === "budgeting" && activeCard === "carry_forward") {
      return dashProjects.filter(p => p.is_carry_forward);
    }
    return [];
  })();

  const showList = activeCard !== null && (
    activeTab === "pipeline" ||
    activeTab === "execution" ||
    (activeTab === "financials" && activeCard === "payments_pending") ||
    (activeTab === "budgeting" && activeCard === "carry_forward")
  );

  if (loading) return <div style={{ flex:1, display:"flex", alignItems:"center", justifyContent:"center", color:T.muted, fontSize:13 }}>Loading portfolio data…</div>;
  if (err)     return <div style={{ flex:1, display:"flex", flexDirection:"column", alignItems:"center", justifyContent:"center", gap:12 }}><AlertCircle color="#F87171" /><span style={{ color:"#F87171", fontSize:13 }}>{err}</span><button onClick={load} style={{ padding:"6px 16px", background:NAVY, color:"#fff", border:"none", borderRadius:6, cursor:"pointer", fontSize:12 }}>Retry</button></div>;
  if (!data) return null;

  const d = data;
  const good = "#2DD4BF", warn = "#F59E0B", bad = "#F87171";
  const healthColor = d.portfolio_health === "Good" ? good : d.portfolio_health === "At Risk" ? warn : bad;

  const TABS = [
    { id:"budgeting",  label:"CAPEX Budget",     icon:"📋" },
    { id:"pipeline",   label:"PDD Status",        icon:"🔁" },
    { id:"execution",  label:"Project Health",    icon:"⚡" },
    { id:"financials", label:"Payments Status",   icon:"💰" },
  ];

  return (
    <div style={{ flex:1, overflow:"auto", padding:"20px 24px", display:"flex", flexDirection:"column", gap:20 }}>

      {/* ── HERO ── */}
      <div style={{ background:T.card, border:"1px solid "+T.border, borderRadius:12, padding:"20px 28px", display:"flex", alignItems:"center", gap:32, borderTop:"3px solid "+GOLD }}>
        <div>
          <div style={{ fontSize:10, color:T.muted, textTransform:"uppercase", letterSpacing:1.5, marginBottom:8, fontWeight:600 }}>Portfolio Health</div>
          <div style={{ display:"flex", alignItems:"center", gap:9 }}>
            <div style={{ width:10, height:10, borderRadius:"50%", background:healthColor, boxShadow:"0 0 10px "+healthColor }} />
            <div style={{ fontSize:30, fontWeight:700, color:healthColor, fontFamily:"DM Serif Display,serif" }}>{d.portfolio_health}</div>
          </div>
          <div style={{ fontSize:11, color:T.muted, marginTop:4 }}>CPI ≥ 0.95 · SPI ≥ 0.95 thresholds</div>
        </div>
        <div style={{ width:1, height:56, background:"rgba(255,255,255,0.12)" }} />
        <div style={{ textAlign:"center" }}>
          <div style={{ fontSize:10, color:T.muted, letterSpacing:1.5, marginBottom:6, fontWeight:600, textTransform:"uppercase" }}>CPI</div>
          <div style={{ fontSize:30, fontWeight:700, color:T.text, fontFamily:"DM Serif Display,serif" }}>{fmtR(d.portfolio_cpi)}</div>
          <div style={{ fontSize:11, color:d.portfolio_cpi >= 0.95 ? good : bad }}>Cost performance</div>
        </div>
        <div style={{ width:1, height:56, background:"rgba(255,255,255,0.12)" }} />
        <div style={{ textAlign:"center" }}>
          <div style={{ fontSize:10, color:T.muted, letterSpacing:1.5, marginBottom:6, fontWeight:600, textTransform:"uppercase" }}>SPI</div>
          <div style={{ fontSize:30, fontWeight:700, color:T.text, fontFamily:"DM Serif Display,serif" }}>{fmtR(d.portfolio_spi)}</div>
          <div style={{ fontSize:11, color:d.portfolio_spi >= 0.95 ? good : bad }}>Schedule performance</div>
        </div>
        <div style={{ marginLeft:"auto", textAlign:"right" }}>
          <div style={{ fontSize:11, color:T.muted, marginBottom:4 }}>Total CAPEX Portfolio</div>
          <div style={{ fontSize:26, fontWeight:700, color:GOLD, fontFamily:"DM Serif Display,serif" }}>PKR {fmtM(d.total_capex)}</div>
          <div style={{ fontSize:11, color:T.muted }}>{d.total_projects} projects · FY 2026-27</div>
        </div>
      </div>

      {/* ── TAB BAR ── */}
      <div style={{ display:"flex", borderBottom:"2px solid "+T.border, gap:0 }}>
        {TABS.map((tab, i) => {
          const isActive = activeTab === tab.id;
          return (
            <button key={tab.id} onClick={() => switchTab(tab.id)}
              style={{
                padding:"12px 28px", border:"none", borderBottom: isActive ? "2px solid "+GOLD : "2px solid transparent",
                marginBottom:"-2px", cursor:"pointer", fontFamily:"Inter,sans-serif",
                fontSize:13, fontWeight: isActive ? 700 : 500, letterSpacing:0.2,
                background:"transparent", color: isActive ? GOLD : T.muted,
                transition:"all .18s", whiteSpace:"nowrap",
              }}>
              <span style={{ display:"flex", alignItems:"center", gap:8 }}>
                {tab.icon && <span style={{ fontSize:14, opacity: isActive ? 1 : 0.6 }}>{tab.icon}</span>}
                {tab.label}
              </span>
            </button>
          );
        })}
      </div>

      {/* ── KPI CARDS ── */}
      {(activeTab === "pipeline" || activeTab === "execution") && (
        <div style={{ fontSize:11, color:T.dim, textAlign:"center", letterSpacing:0.3 }}>
          {activeCard ? "↓ Scroll down to see the project list — click the same card to collapse" : "Click any card below to view its projects"}
        </div>
      )}
      {activeTab === "budgeting" && (
        <div style={{ display:"flex", gap:10 }}>
          <EditableKCard T={T} label="SU Requested"   featured accent={GOLD} canEdit={canEdit} kpiKey="su_requested"    onSave={saveKPI} {...kv("su_requested",   fmtM(d.su_requested_total),  "From "+(d.total_projects-(d.carry_forward_count||0))+" new proposals")} />
          <EditableKCard T={T} label="DF Recommended"          canEdit={canEdit} kpiKey="df_recommended"  onSave={saveKPI} {...kv("df_recommended", fmtM(d.df_recommended_total), "After Finance Director review")} />
          <EditableKCard T={T} label="Budget Reduction"        canEdit={canEdit} kpiKey="budget_reduction" accent={bad}   onSave={saveKPI} {...kv("budget_reduction", fmtM(d.budget_reduction), "SU to DF variance")} />
          <EditableKCard T={T} label="Carry Forward"  featured accent={GOLD} canEdit={canEdit} kpiKey="carry_forward"   onSave={saveKPI} onCardClick={() => toggleCard("carry_forward")} isSelected={activeCard==="carry_forward"} {...kv("carry_forward",   "PKR "+fmtM(d.carry_forward_amount), (d.carry_forward_count||0)+" projects from prior FY")} />
          <EditableKCard T={T} label="Total Projects" featured          canEdit={canEdit} kpiKey="total_projects"  onSave={saveKPI} {...kv("total_projects",  String(d.total_projects), "Capex FY 26-27 projects")} />
        </div>
      )}
      {activeTab === "pipeline" && (
        <div style={{ display:"flex", gap:10 }}>
          <EditableKCard T={T} label="PDDs Not Submitted" canEdit={canEdit} kpiKey="pdd_not_submitted" onSave={saveKPI} onCardClick={() => toggleCard("pdd_not_submitted")} isSelected={activeCard==="pdd_not_submitted"} {...kv("pdd_not_submitted", d.pdd_not_submitted_count||0, "Awaiting PDDs submission")} />
          <EditableKCard T={T} label="PDDs Submitted" canEdit={canEdit} kpiKey="pdds_submitted" onSave={saveKPI} onCardClick={() => toggleCard("pdds_submitted")} isSelected={activeCard==="pdds_submitted"} {...kv("pdds_submitted", d.pdds_submitted, "Awaiting DF Review")} />
          <EditableKCard T={T} label="DF Review"      canEdit={canEdit} kpiKey="in_df"          accent={GOLD}   onSave={saveKPI} onCardClick={() => toggleCard("in_df")}           isSelected={activeCard==="in_df"}           {...kv("in_df",          d.in_df,           "With Finance Director")} />
          <EditableKCard T={T} label="ED Review"      canEdit={canEdit} kpiKey="in_ed"          accent={GOLD}   onSave={saveKPI} onCardClick={() => toggleCard("in_ed")}           isSelected={activeCard==="in_ed"}           {...kv("in_ed",          d.in_ed,           "With Executive Director")} />
          <EditableKCard T={T} label="MT Review"      canEdit={canEdit} kpiKey="in_mt"          accent={GOLD}   onSave={saveKPI} onCardClick={() => toggleCard("in_mt")}           isSelected={activeCard==="in_mt"}           {...kv("in_mt",          d.in_mt,           "With Management Team")} />
          <EditableKCard T={T} label="Approved"       canEdit={canEdit} kpiKey="approved"       accent={good}   featured onSave={saveKPI} onCardClick={() => toggleCard("approved")} isSelected={activeCard==="approved"}        {...kv("approved", d.approved_count, "Sanctioned for execution")} />
        </div>
      )}
      {activeTab === "execution" && (
        <div style={{ display:"flex", gap:10 }}>
          <EditableKCard T={T} label="Active Projects" featured canEdit={canEdit} kpiKey="active_projects" onSave={saveKPI} onCardClick={() => toggleCard("active_projects")} isSelected={activeCard==="active_projects"} {...kv("active_projects", d.approved_count,      "Currently executing")} />
          <EditableKCard T={T} label="On Schedule"             canEdit={canEdit} kpiKey="on_schedule"     accent={good}   onSave={saveKPI} onCardClick={() => toggleCard("on_schedule")}     isSelected={activeCard==="on_schedule"}     {...kv("on_schedule",     d.on_time_count,        "SPI ≥ 0.95")} />
          <EditableKCard T={T} label="Delayed"                 canEdit={canEdit} kpiKey="delayed"         accent={warn}   onSave={saveKPI} onCardClick={() => toggleCard("delayed")}         isSelected={activeCard==="delayed"}         {...kv("delayed",         d.delayed_count,        "SPI < 0.95")} />
          <EditableKCard T={T} label="Over Budget"             canEdit={canEdit} kpiKey="over_budget"     accent={bad}    onSave={saveKPI} onCardClick={() => toggleCard("over_budget")}     isSelected={activeCard==="over_budget"}     {...kv("over_budget",     d.over_budget_count,    "CPI < 0.95")} />
          <EditableKCard T={T} label="Change in Scope"         canEdit={canEdit} kpiKey="scope_change"    accent="#A78BFA" onSave={saveKPI} onCardClick={() => toggleCard("scope_change")}    isSelected={activeCard==="scope_change"}    {...kv("scope_change",    d.scope_change_count||0,"Scope revised projects")} />
          <EditableKCard T={T} label="Closed"                  canEdit={canEdit} kpiKey="closed"          accent={T.muted} onSave={saveKPI} onCardClick={() => toggleCard("closed")}        isSelected={activeCard==="closed"}          {...kv("closed",          d.closed_count,      "Completed & handed over")} />
        </div>
      )}
      {activeTab === "financials" && (
        <div style={{ display:"flex", gap:10 }}>
          <EditableKCard T={T} label="Total CAPEX"      featured accent={GOLD} canEdit={canEdit} kpiKey="total_capex"       onSave={saveKPI} {...kv("total_capex",        fmtM(d.total_capex),              "Full portfolio value")} />
          <EditableKCard T={T} label="Budget Released"           canEdit={canEdit} kpiKey="budget_released"    onSave={saveKPI} {...kv("budget_released",     fmtM(d.budget_consumed),          fmtP((d.budget_consumed/d.total_capex)*100)+" of total CAPEX")} />
          <EditableKCard T={T} label="Remaining CAPEX"  accent={good} canEdit={canEdit} kpiKey="remaining_capex"  onSave={saveKPI} {...kv("remaining_capex",    fmtM(d.budget_remaining),         fmtP((d.budget_remaining/d.total_capex)*100)+" available")} />
          <EditableKCard T={T} label="Payments Made"             canEdit={canEdit} kpiKey="payments_made"      onSave={saveKPI} {...kv("payments_made",       fmtM(d.payments_made_total),      "Finance-confirmed transfers")} />
          <EditableKCard T={T} label="Payments Pending" accent={warn} canEdit={canEdit} kpiKey="payments_pending" onSave={saveKPI} onCardClick={() => toggleCard("payments_pending")} isSelected={activeCard==="payments_pending"} {...kv("payments_pending",  fmtM(d.payments_pending_amount),  d.payments_pending_count+" projects awaiting transfer")} />
        </div>
      )}

      {/* ── PROJECT LIST ── */}
      <div id="dash-project-list">
        {showList && (
          <DashProjectList T={T} projects={filteredProjects} tab={activeTab} activeCard={activeCard} onSelectProject={onSelectProject} />
        )}
      </div>

      {/* ── BREAKDOWN: Planned vs Actual ── */}
      <BreakdownSection T={T} session={session} />

    </div>
  );
}

// ─── PROJECTS PAGE ────────────────────────────────────────────────────────────
const STAGE_FILTERS = [
  { id:"all",   label:"All" },
  { id:"pdd_not_submitted", label:"PDD Not Submitted" },
  { id:"identified", label:"PDD Submitted" },
  { id:"pipeline",   label:"Pipeline" },
  { id:"approved",   label:"Approved" },
  { id:"closed",     label:"Closed" },
  { id:"cf",         label:"Carry Forward" },
];

function StageBadge({ stage, size = 11 }) {
  const s = STAGE[stage] || { label:stage, light:"#aaa", dark:"rgba(170,170,170,0.15)" };
  return (
    <span style={{
      display:"inline-flex", alignItems:"center", padding:"2px 8px", borderRadius:20,
      background:s.dark, color:s.light, fontSize:size, fontWeight:600, whiteSpace:"nowrap",
    }}>{s.label}</span>
  );
}

// ─── PROJECT FORM MODAL (add / edit) ─────────────────────────────────────────
const Sec = ({T,title})=><div style={{fontSize:10,fontWeight:700,color:T.muted,letterSpacing:2,textTransform:"uppercase",margin:"14px 0 10px",paddingBottom:6,borderBottom:`1px solid ${T.border}`}}>{title}</div>;
const Row = ({children,mb=14})=><div style={{display:"flex",gap:12,marginBottom:mb}}>{children}</div>;
const Col = ({children,flex=1})=><div style={{flex}}>{children}</div>;

function ProjectFormModal({ T, session, project, lookups, onSaved, onClose }) {
  const isEdit = !!project;
  const initForm = () => ({
    code:project?.code||"", name:project?.name||"",
    fiscal_year:project?.fiscal_year||"",
    strategic_priority:project?.strategic_priority||"",
    sector_id:project?.sector_id||"", region_id:project?.region_id||"",
    segment_id:project?.segment_id||"", cost_center_id:project?.cost_center_id||"",
    campus:project?.campus||"",
    project_type:project?.project_type||"", priority:project?.priority||"",
    workflow_stage:project?.workflow_stage||"identified",
    is_carry_forward:project?.is_carry_forward||false, payments_pending:project?.payments_pending||false,
    scope_change:project?.scope_change||false,
    su_requested_amount:project?.su_requested_amount||0, df_recommended_amount:project?.df_recommended_amount||0,
    bac:project?.bac||0, amount_released:project?.amount_released||0, payments_made:project?.payments_made||0,
    budget_release_date:project?.budget_release_date||"",
    start_date:project?.start_date||"", end_date:project?.end_date||"",
    actual_start_date:project?.actual_start_date||"", actual_end_date:project?.actual_end_date||"",
    duration_months:project?.duration_months||"", pct_complete:project?.pct_complete||0,
    manual_schedule_flag:project?.manual_schedule_flag||"", manual_budget_flag:project?.manual_budget_flag||"",
    notes:project?.notes||"",
  });
  const [form, setForm] = useState(initForm());
  const [saving, setSaving] = useState(false);
  const [err, setErr] = useState(null);
  const set = (k,v) => setForm(f=>({...f,[k]:v}));

  const save = async () => {
    if (!form.code.trim()) return setErr("Project code is required.");
    if (!form.name.trim()) return setErr("Project name is required.");
    setErr(null); setSaving(true);
    try {
      const payload = { ...form,
        fiscal_year:form.fiscal_year||null,
        strategic_priority:form.strategic_priority||null,
        sector_id:form.sector_id||null, region_id:form.region_id||null,
        segment_id:form.segment_id||null, cost_center_id:form.cost_center_id||null,
        campus:form.campus||null,
        project_type:form.project_type||null, priority:form.priority||null, start_date:form.start_date||null,
        end_date:form.end_date||null,
        actual_start_date:form.actual_start_date||null, actual_end_date:form.actual_end_date||null,
        notes:form.notes||null,
        duration_months:form.duration_months?parseInt(form.duration_months):null,
        manual_schedule_flag:form.manual_schedule_flag||null, manual_budget_flag:form.manual_budget_flag||null,
        su_requested_amount:parseFloat(form.su_requested_amount)||0,
        df_recommended_amount:parseFloat(form.df_recommended_amount)||0,
        bac:parseFloat(form.bac)||0, amount_released:parseFloat(form.amount_released)||0,
        budget_release_date:form.budget_release_date||null,
        payments_made:parseFloat(form.payments_made)||0, pct_complete:parseFloat(form.pct_complete)||0,
        scope_change:form.scope_change||false,
      };
      if (isEdit) {
        await supa(`/rest/v1/projects?id=eq.${project.id}`,{method:"PATCH",body:JSON.stringify(payload),headers:{"Prefer":"return=minimal"}},session.access_token);
      } else {
        await supa("/rest/v1/projects",{method:"POST",body:JSON.stringify(payload),headers:{"Prefer":"return=minimal"}},session.access_token);
      }
      await supa("/rest/v1/activity_log",{method:"POST",body:JSON.stringify({
        actor_id:session.user_id,actor_name:session.full_name||session.username,actor_role:session.role,
        action:isEdit?"updated":"created",entity_type:"projects",entity_id:isEdit?project.id:null,
        summary:`${isEdit?"Updated":"Created"} project ${form.code}: ${form.name}`,
      }),headers:{"Prefer":"return=minimal"}},session.access_token);
      onSaved();
    } catch(e) { setErr(e.message); }
    setSaving(false);
  };

  const inp = {background:T.inputBg,border:`1px solid ${T.inputBorder}`,borderRadius:7,padding:"8px 10px",fontSize:13,color:T.text,fontFamily:"Inter,sans-serif",outline:"none",width:"100%",boxSizing:"border-box"};
  const sel = {...inp,cursor:"pointer"};
  const lbl = {display:"block",fontSize:10,fontWeight:700,color:T.muted,letterSpacing:1,textTransform:"uppercase",marginBottom:5};

  return (
    <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.6)",zIndex:300,display:"flex",alignItems:"center",justifyContent:"center",padding:20}}>
      <div style={{background:T.card,border:`1px solid ${T.border}`,borderRadius:14,padding:"26px 28px",width:700,maxHeight:"90vh",overflow:"auto",boxShadow:"0 24px 60px rgba(0,0,0,0.5)"}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:16,paddingBottom:14,borderBottom:`1px solid ${T.border}`}}>
          <div style={{fontSize:17,fontWeight:700,color:T.text,fontFamily:"DM Serif Display,serif"}}>{isEdit?`Edit — ${project.code}`:"New Project"}</div>
          <button onClick={onClose} style={{background:"none",border:"none",cursor:"pointer",color:T.muted,display:"flex",padding:2}}><X size={17}/></button>
        </div>
        {err&&<div style={{marginBottom:12,padding:"9px 12px",borderRadius:7,background:"rgba(248,113,113,0.1)",border:"1px solid rgba(248,113,113,0.3)",color:"#F87171",fontSize:13,display:"flex",gap:8}}><span>⚠</span>{err}</div>}

        <Sec T={T} title="Basic"/>
        <Row>
          <Col flex={1}><label style={lbl}>Code *</label><input value={form.code} onChange={e=>set("code",e.target.value)} placeholder="PRJ-2627-099" style={inp}/></Col>
          <Col flex={3}><label style={lbl}>Name *</label><input value={form.name} onChange={e=>set("name",e.target.value)} placeholder="Project name" style={inp}/></Col>
        </Row>

        <Sec T={T} title="Classification"/>
        <Row>
          <Col><label style={lbl}>Segment</label><select value={form.sector_id} onChange={e=>set("sector_id",e.target.value)} style={sel}><option value="">— None —</option>{lookups.sectors.map(s=><option key={s.id} value={s.id}>{s.name}</option>)}</select></Col>
          <Col><label style={lbl}>Region</label><select value={form.region_id} onChange={e=>set("region_id",e.target.value)} style={sel}><option value="">— None —</option>{lookups.regions.map(r=><option key={r.id} value={r.id}>{r.name}</option>)}</select></Col>
          <Col><label style={lbl}>Organization</label><select value={form.segment_id} onChange={e=>set("segment_id",e.target.value)} style={sel}><option value="">— None —</option>{lookups.segments.map(s=><option key={s.id} value={s.id}>{s.name}</option>)}</select></Col>
        </Row>
        <Row mb={0}>
          <Col flex={2}><label style={lbl}>Cost Centre</label><select value={form.cost_center_id} onChange={e=>set("cost_center_id",e.target.value)} style={sel}><option value="">— None —</option>{lookups.cost_centers.map(c=><option key={c.id} value={c.id}>{c.name}</option>)}</select></Col>
          <Col flex={2}><label style={lbl}>Campus / Site</label><input type="text" value={form.campus} onChange={e=>set("campus",e.target.value)} placeholder="e.g. Islamabad Campus, I-14" style={inp}/></Col>
          <Col><label style={lbl}>Project Type</label><input value={form.project_type} onChange={e=>set("project_type",e.target.value)} placeholder="e.g. Construction" style={inp}/></Col>
          <Col><label style={lbl}>Priority</label><select value={form.priority} onChange={e=>set("priority",e.target.value)} style={sel}><option value="">— None —</option><option value="top_priority">Top Priority</option><option value="second_priority">2nd Priority</option><option value="third_priority">3rd Priority</option><option value="carry_forward">Carry Forward</option></select></Col>
        </Row>

        <Sec T={T} title="Workflow"/>
        <Row mb={0}>
          <Col flex={2}><label style={lbl}>Stage</label><select value={form.workflow_stage} onChange={e=>set("workflow_stage",e.target.value)} style={sel}><option value="pdd_not_submitted">PDD Not Submitted</option><option value="identified">PDD Submitted</option><option value="df_review">DF Review</option><option value="ed_review">ED Review</option><option value="mt_review">MT Review</option><option value="approved">Approved</option><option value="closed">Closed</option></select></Col>
          <Col>
            <label style={{...lbl,marginBottom:10}}>Flags</label>
            <div style={{display:"flex",flexDirection:"column",gap:7}}>
              <label style={{display:"flex",alignItems:"center",gap:7,cursor:"pointer",fontSize:13,color:T.text}}><input type="checkbox" checked={form.is_carry_forward} onChange={e=>set("is_carry_forward",e.target.checked)} style={{accentColor:GOLD}}/>Carry Forward</label>
              <label style={{display:"flex",alignItems:"center",gap:7,cursor:"pointer",fontSize:13,color:T.text}}><input type="checkbox" checked={form.payments_pending} onChange={e=>set("payments_pending",e.target.checked)} style={{accentColor:GOLD}}/>Payments Pending</label>
            </div>
          </Col>
        </Row>

        <Sec T={T} title="Financials (PKR Millions)"/>
        <Row>
          <Col><label style={lbl}>SU Requested</label><input type="number" step="0.1" value={form.su_requested_amount} onChange={e=>set("su_requested_amount",e.target.value)} style={inp}/></Col>
          <Col><label style={lbl}>DF Recommended</label><input type="number" step="0.1" value={form.df_recommended_amount} onChange={e=>set("df_recommended_amount",e.target.value)} style={inp}/></Col>
          <Col><label style={lbl}>BAC (Sanctioned)</label><input type="number" step="0.1" value={form.bac} onChange={e=>set("bac",e.target.value)} style={inp}/></Col>
        </Row>
        <Row mb={0}>
          <Col><label style={lbl}>Amount Released</label><input type="number" step="0.1" value={form.amount_released} onChange={e=>set("amount_released",e.target.value)} style={inp}/></Col>
          <Col><label style={lbl}>Budget Released Date</label><input type="date" value={form.budget_release_date} onChange={e=>set("budget_release_date",e.target.value)} style={inp}/></Col>
          <Col><label style={lbl}>Payments Made</label><input type="number" step="0.1" value={form.payments_made} onChange={e=>set("payments_made",e.target.value)} style={inp}/></Col>
          <Col/>
        </Row>

        <Sec T={T} title="Schedule"/>
        <Row>
          <Col><label style={lbl}>Planned Start Date</label><input type="date" value={form.start_date} onChange={e=>set("start_date",e.target.value)} style={inp}/></Col>
          <Col><label style={lbl}>Planned End Date</label><input type="date" value={form.end_date} onChange={e=>set("end_date",e.target.value)} style={inp}/></Col>
          <Col><label style={lbl}>Duration (months)</label><input type="number" value={form.duration_months} onChange={e=>set("duration_months",e.target.value)} style={inp}/></Col>
          <Col><label style={lbl}>Actual Start Date</label><input type="date" value={form.actual_start_date} onChange={e=>set("actual_start_date",e.target.value)} style={inp}/></Col>
          <Col><label style={lbl}>Actual End Date <span style={{fontSize:10,color:T.dim}}>(closed only)</span></label><input type="date" value={form.actual_end_date} onChange={e=>set("actual_end_date",e.target.value)} style={inp}/></Col>
        </Row>
        <Row mb={0}>
          <Col><label style={lbl}>% Complete</label><input type="number" min="0" max="100" value={form.pct_complete} onChange={e=>set("pct_complete",e.target.value)} style={inp}/></Col>
          <Col><label style={lbl}>Schedule Status</label><select value={form.manual_schedule_flag} onChange={e=>set("manual_schedule_flag",e.target.value)} style={sel}><option value="">— Auto —</option><option value="not_started">Not Started</option><option value="on_time">On Time</option><option value="delayed">Delayed</option></select></Col>
          <Col><label style={lbl}>Budget Status</label><select value={form.manual_budget_flag} onChange={e=>set("manual_budget_flag",e.target.value)} style={sel}><option value="">— Auto —</option><option value="not_started">Not Started</option><option value="within">Within Budget</option><option value="over">Over Budget</option></select></Col>
        </Row>

        <Sec T={T} title="Additional"/>
        <Row>
          <Col><label style={lbl}>Fiscal Year</label><input value={form.fiscal_year} onChange={e=>set("fiscal_year",e.target.value)} placeholder="e.g. FY 2026-27" style={inp}/></Col>
          <Col flex={2}><label style={lbl}>Strategic Priority</label><input value={form.strategic_priority} onChange={e=>set("strategic_priority",e.target.value)} placeholder="e.g. Infrastructure Development" style={inp}/></Col>
        </Row>
        <Sec T={T} title="Notes"/>
        <textarea value={form.notes} onChange={e=>set("notes",e.target.value)} rows={3} placeholder="Additional notes…" style={{...inp,resize:"vertical",lineHeight:1.6,marginBottom:18}}/>

        <div style={{display:"flex",gap:10}}>
          <button onClick={onClose} style={{flex:1,padding:"10px",borderRadius:8,border:`1px solid ${T.border}`,background:"none",color:T.muted,cursor:"pointer",fontSize:13,fontFamily:"Inter,sans-serif"}}>Cancel</button>
          <button onClick={save} disabled={saving} style={{flex:2,padding:"10px",borderRadius:8,border:"none",background:saving?T.muted:NAVY,color:"#fff",cursor:saving?"default":"pointer",fontSize:13,fontWeight:700,fontFamily:"Inter,sans-serif"}}>{saving?"Saving…":isEdit?"Save Changes":"Create Project"}</button>
        </div>
      </div>
    </div>
  );
}

