// ─── UPDATES & COMMENTS ───────────────────────────────────────────────────────
const timeAgo = d => {
  const s = (Date.now() - new Date(d)) / 1000;
  if (s < 60)    return "just now";
  if (s < 3600)  return `${Math.floor(s/60)}m ago`;
  if (s < 86400) return `${Math.floor(s/3600)}h ago`;
  if (s < 604800)return `${Math.floor(s/86400)}d ago`;
  return new Date(d).toLocaleDateString("en-GB", { day:"numeric", month:"short" });
};

const buildTree = comments => {
  const roots   = comments.filter(c => !c.parent_id);
  const replies = {};
  comments.filter(c => c.parent_id).forEach(c => {
    (replies[c.parent_id] = replies[c.parent_id] || []).push(c);
  });
  return { roots, replies };
};

function CommentBubble({ T, comment, replies, onReply, depth }) {
  const ROLE = { pmo:{ c:GOLD, label:"Admin" }, project_manager:{ c:"#60A5FA", label:"PM" }, guest:{ c:"#9CA3AF", label:"Guest" } };
  const role = comment.author_role || comment.user_profiles?.role;
  const rc   = ROLE[role] || { c:"#9CA3AF", label:"?" };
  const name = comment.author_name || comment.user_profiles?.full_name || comment.user_profiles?.username;
  const deleted = !name;
  const init = deleted ? "✕" : name[0].toUpperCase();
  return (
    <div style={{ marginLeft: depth ? 36 : 0, marginBottom:10 }}>
      <div style={{ background:T.card2, borderRadius:10, padding:"11px 14px", border:`1px solid ${T.border}` }}>
        <div style={{ display:"flex", alignItems:"center", gap:8, marginBottom:7 }}>
          <div style={{ width:26, height:26, borderRadius:"50%", background:NAVY, display:"flex", alignItems:"center", justifyContent:"center", fontSize:11, fontWeight:700, color:"#fff", flexShrink:0 }}>{init}</div>
          <span style={{ fontSize:13, fontWeight:600, color:deleted ? T.dim : T.text }}>{deleted ? "Deleted User" : name}</span>
          <span style={{ fontSize:10, fontWeight:700, color:rc.c, background:`${rc.c}18`, padding:"2px 8px", borderRadius:20 }}>{rc.label}</span>
          <span style={{ fontSize:11, color:T.dim, marginLeft:"auto" }}>{timeAgo(comment.created_at)}</span>
        </div>
        <div style={{ fontSize:13.5, color:T.text, lineHeight:1.65, whiteSpace:"pre-wrap", wordBreak:"break-word" }}>{comment.body}</div>
        {!depth && onReply && (
          <button onClick={() => onReply(comment)} style={{ marginTop:7, background:"none", border:"none", cursor:"pointer", fontSize:11, color:T.muted, padding:0, fontFamily:"Inter,sans-serif" }}>
            ↩ Reply
          </button>
        )}
      </div>
      {(replies || []).map(r => (
        <CommentBubble key={r.id} T={T} comment={r} replies={[]} onReply={null} depth={1} />
      ))}
    </div>
  );
}

function ComposeBox({ T, value, onChange, onPost, posting, replyingTo, onCancelReply, canPost }) {
  if (!canPost) return (
    <div style={{ padding:"14px 20px", borderTop:`1px solid ${T.border}`, color:T.dim, fontSize:12, textAlign:"center", flexShrink:0 }}>
      You have read-only access. Comments are view-only for Guests.
    </div>
  );
  return (
    <div style={{ padding:"14px 20px", borderTop:`1px solid ${T.border}`, flexShrink:0, background:T.headerBg }}>
      {replyingTo && (
        <div style={{ display:"flex", alignItems:"center", gap:8, padding:"5px 10px", background:T.card2, borderRadius:6, marginBottom:8, fontSize:12, color:T.muted }}>
          <span>↩ Replying to <strong style={{ color:T.text }}>{replyingTo.author_name || replyingTo.user_profiles?.full_name || replyingTo.user_profiles?.username || "Deleted User"}</strong></span>
          <button onClick={onCancelReply} style={{ marginLeft:"auto", background:"none", border:"none", cursor:"pointer", color:T.dim, fontSize:16, padding:0, lineHeight:1 }}>×</button>
        </div>
      )}
      <textarea value={value} onChange={e => onChange(e.target.value)}
        placeholder="Write a comment… (Ctrl+Enter to post)"
        rows={3}
        onKeyDown={e => { if (e.key==="Enter" && (e.ctrlKey||e.metaKey)) onPost(); }}
        style={{ width:"100%", background:T.inputBg, border:`1px solid ${T.inputBorder}`, borderRadius:8, padding:"9px 12px", fontSize:13, color:T.text, fontFamily:"Inter,sans-serif", outline:"none", resize:"vertical", boxSizing:"border-box" }}
      />
      <div style={{ display:"flex", justifyContent:"flex-end", marginTop:8 }}>
        <button onClick={onPost} disabled={posting || !value.trim()} style={{
          padding:"7px 20px", borderRadius:7, border:"none",
          background: posting||!value.trim() ? T.muted : NAVY,
          color:"#fff", cursor:posting||!value.trim()?"default":"pointer",
          fontSize:12, fontWeight:700, fontFamily:"Inter,sans-serif",
          boxShadow: posting||!value.trim() ? "none" : "0 3px 10px rgba(24,80,120,0.3)",
        }}>{posting ? "Posting…" : "Post Comment"}</button>
      </div>
    </div>
  );
}

function UpdatesPage({ T, session, defaultProjectId, onClearDefault }) {
  const [projects,       setProjects]       = useState([]);
  const [summary,        setSummary]        = useState([]); // {id, project_id, is_read_by_pmo, created_at, user_profiles:{role}}
  const [userAssignments,setUserAssignments]= useState(new Set());
  const [selId,          setSelId]          = useState(null);
  const [selProject,     setSelProject]     = useState(null);
  const [thread,         setThread]         = useState([]);
  const [loadingThread,  setLoadingThread]  = useState(false);
  const [view, setView] = useState(session.role === "project_manager" ? "all" : "inbox");
  const [replyingTo,     setReplyingTo]     = useState(null);
  const [body,           setBody]           = useState("");
  const [posting,        setPosting]        = useState(false);

  // ── Load ────────────────────────────────────────────────────────────────────
  const loadSummary = useCallback(async () => {
    try {
      const [projData, sumData] = await Promise.all([
        supa("/rest/v1/projects?select=id,code,name&order=code.asc", {}, session.access_token),
        supa("/rest/v1/comments?select=id,project_id,is_read_by_pmo,created_at,author_role,user_profiles(role)&order=created_at.desc", {}, session.access_token),
      ]);
      setProjects(projData);
      setSummary(sumData);

      if (session.role === "project_manager") {
        const assigns = await supa("/rest/v1/project_assignments?select=project_id&user_id=eq."+session.user_id, {}, session.access_token);
        setUserAssignments(new Set(assigns.map(a => a.project_id)));
      }
    } catch(_) {}
  }, [session.access_token, session.role, session.user_id]);

  useEffect(() => { loadSummary(); }, [loadSummary]);

  // Auto-select project when coming from Project Detail "Go to Discussion"
  useEffect(() => {
    if (defaultProjectId && projects.length > 0 && !selId) {
      const p = projects.find(pr => pr.id === defaultProjectId);
      if (p) { selectProject(p); onClearDefault?.(); }
    }
  }, [defaultProjectId, projects]);

  const loadThread = useCallback(async id => {
    setLoadingThread(true); setThread([]);
    try {
      const data = await supa(
        `/rest/v1/comments?project_id=eq.${id}&select=id,body,parent_id,author_id,author_name,author_role,is_read_by_pmo,created_at,user_profiles(username,full_name,role)&order=created_at.asc`,
        {}, session.access_token
      );
      setThread(data);

      // PMO: mark unread as read
      if (session.role === "pmo") {
        const unread = data.filter(c => !c.is_read_by_pmo && (c.author_role || c.user_profiles?.role) !== "pmo");
        if (unread.length > 0) {
          await supa(`/rest/v1/comments?project_id=eq.${id}&is_read_by_pmo=eq.false`,
            { method:"PATCH", body:JSON.stringify({is_read_by_pmo:true}), headers:{"Prefer":"return=minimal"} },
            session.access_token
          );
          loadSummary();
        }
      }
    } catch(_) {}
    setLoadingThread(false);
  }, [session.access_token, session.role, loadSummary]);

  const selectProject = useCallback(p => {
    setSelId(p.id); setSelProject(p); setReplyingTo(null); setBody("");
    loadThread(p.id);
  }, [loadThread]);

  // ── Post ────────────────────────────────────────────────────────────────────
  const postComment = async () => {
    if (!body.trim() || !selId) return;
    setPosting(true);
    try {
      await supa("/rest/v1/comments", {
        method:"POST",
        body: JSON.stringify({ project_id:selId, author_id:session.user_id, author_name:(session.full_name||session.username), author_role:session.role, body:body.trim(), parent_id:replyingTo?.id||null }),
        headers:{"Prefer":"return=minimal"},
      }, session.access_token);
      setBody(""); setReplyingTo(null);
      await loadThread(selId);
      await loadSummary();
    } catch(_) {}
    setPosting(false);
  };

  // ── Derived ─────────────────────────────────────────────────────────────────
  const commentsByProject = useMemo(() => {
    const m = {};
    summary.forEach(c => {
      if (!m[c.project_id]) m[c.project_id] = { total:0, unread:0, lastAt:null };
      m[c.project_id].total++;
      if (!c.is_read_by_pmo && (c.author_role || c.user_profiles?.role) !== "pmo") m[c.project_id].unread++;
      if (!m[c.project_id].lastAt || c.created_at > m[c.project_id].lastAt) m[c.project_id].lastAt = c.created_at;
    });
    return m;
  }, [summary]);

  const inboxCount = useMemo(() =>
    Object.values(commentsByProject).reduce((s, v) => s + v.unread, 0), [commentsByProject]);

  const displayProjects = useMemo(() => {
    // For PMs: the /projects fetch is already RLS-filtered to their assigned projects.
    // For PMO/Guest: all projects.
    let list = [...projects];
    if (view === "inbox") {
      list = list.filter(p => (commentsByProject[p.id]?.unread||0) > 0);
    } else {
      // Show all projects; sort by most recent comment first
      list.sort((a,b) => {
        const at = commentsByProject[a.id]?.lastAt || "0";
        const bt = commentsByProject[b.id]?.lastAt || "0";
        return bt.localeCompare(at);
      });
    }
    return list;
  }, [projects, view, commentsByProject]);

  // PMs can post on any project they can see (RLS already restricts to assigned projects)
  const canPost = session.role === "pmo" || session.role === "project_manager" || session.role === "guest";

  const { roots, replies } = useMemo(() => buildTree(thread), [thread]);

  // ── Render ──────────────────────────────────────────────────────────────────
  return (
    <div style={{ flex:1, display:"flex", overflow:"hidden" }}>

      {/* ── Left sidebar ── */}
      <div style={{ width:280, flexShrink:0, display:"flex", flexDirection:"column", borderRight:`1px solid ${T.border}`, overflow:"hidden" }}>
        {/* Tabs */}
        <div style={{ display:"flex", borderBottom:`1px solid ${T.border}`, flexShrink:0 }}>
          {(session.role === "pmo" ? [
            { id:"inbox", label:"Inbox", badge:inboxCount },
            { id:"all",   label:"All Projects" },
          ] : [
            { id:"all", label:"My Projects" },
          ]).map(tab => (
            <button key={tab.id} onClick={() => setView(tab.id)} style={{
              flex:1, padding:"11px 0", background:"none", border:"none", borderBottom:`2px solid ${view===tab.id?GOLD:"transparent"}`,
              color:view===tab.id?GOLD:T.muted, fontSize:12.5, fontWeight:view===tab.id?700:400,
              cursor:"pointer", fontFamily:"Inter,sans-serif", display:"flex", alignItems:"center", justifyContent:"center", gap:6,
            }}>
              {tab.label}
              {tab.badge > 0 && (
                <span style={{ background:"#F87171", color:"#fff", fontSize:10, fontWeight:700, padding:"1px 6px", borderRadius:20 }}>
                  {tab.badge}
                </span>
              )}
            </button>
          ))}
        </div>

        {/* Project list */}
        <div style={{ flex:1, overflow:"auto" }}>
          {displayProjects.length === 0 ? (
            <div style={{ padding:"24px 16px", textAlign:"center", color:T.dim, fontSize:12, lineHeight:1.7 }}>
              {view==="inbox"
                ? "No unread PM updates."
                : session.role === "project_manager"
                  ? "No projects assigned to you yet.\nContact the PMO to get access."
                  : "No projects with comments yet."}
            </div>
          ) : displayProjects.map(p => {
            const cm = commentsByProject[p.id] || { total:0, unread:0 };
            const selected = selId === p.id;
            return (
              <div key={p.id} onClick={() => selectProject(p)} style={{
                padding:"11px 14px", cursor:"pointer", borderBottom:`1px solid ${T.border}`,
                background: selected ? `${NAVY}22` : "transparent",
                borderLeft:`3px solid ${selected ? GOLD : "transparent"}`,
                transition:"background .1s",
              }}>
                <div style={{ display:"flex", alignItems:"center", gap:6 }}>
                  {cm.unread > 0 && <span style={{ width:7, height:7, borderRadius:"50%", background:"#F87171", flexShrink:0 }} />}
                  <span style={{ fontSize:10, color:T.dim, fontFamily:"monospace", flexShrink:0 }}>{p.code}</span>
                  {cm.unread > 0 && (
                    <span style={{ marginLeft:"auto", fontSize:10, fontWeight:700, color:"#F87171", background:"rgba(248,113,113,0.12)", padding:"1px 6px", borderRadius:20 }}>
                      {cm.unread} new
                    </span>
                  )}
                </div>
                <div style={{ fontSize:12.5, color:T.text, marginTop:2, lineHeight:1.3 }}>{p.name}</div>
                {cm.total > 0 && (
                  <div style={{ fontSize:11, color:T.dim, marginTop:4 }}>
                    {cm.total} comment{cm.total!==1?"s":""} · {timeAgo(cm.lastAt)}
                  </div>
                )}
              </div>
            );
          })}
        </div>
      </div>

      {/* ── Right: thread ── */}
      <div style={{ flex:1, display:"flex", flexDirection:"column", overflow:"hidden", minWidth:0 }}>
        {!selId ? (
          <div style={{ flex:1, display:"flex", flexDirection:"column", alignItems:"center", justifyContent:"center", gap:8, color:T.dim }}>
            <div style={{ fontSize:28 }}>💬</div>
            <div style={{ fontSize:14, fontWeight:600, color:T.text }}>Select a project to view updates</div>
            <div style={{ fontSize:12, color:T.dim }}>Comments and progress updates appear here.</div>
          </div>
        ) : (
          <>
            {/* Thread header */}
            <div style={{ padding:"12px 20px", borderBottom:`1px solid ${T.border}`, background:T.headerBg, flexShrink:0 }}>
              <div style={{ fontSize:10, color:T.dim, fontFamily:"monospace" }}>{selProject?.code}</div>
              <div style={{ fontSize:15, fontWeight:700, color:T.text }}>{selProject?.name}</div>
            </div>

            {/* Comments */}
            <div style={{ flex:1, overflow:"auto", padding:"16px 20px" }}>
              {loadingThread ? (
                <div style={{ textAlign:"center", color:T.muted, fontSize:13, paddingTop:40 }}>Loading thread…</div>
              ) : roots.length === 0 ? (
                <div style={{ textAlign:"center", color:T.dim, fontSize:13, paddingTop:40, lineHeight:1.6 }}>
                  No comments yet on this project.<br/>
                  <span style={{ fontSize:12 }}>Be the first to post an update below.</span>
                </div>
              ) : roots.map(c => (
                <CommentBubble
                  key={c.id} T={T} comment={c}
                  replies={replies[c.id] || []}
                  onReply={canPost ? setReplyingTo : null}
                  depth={0}
                />
              ))}
            </div>

            {/* Compose */}
            <ComposeBox
              T={T} value={body} onChange={setBody}
              onPost={postComment} posting={posting}
              replyingTo={replyingTo} onCancelReply={() => setReplyingTo(null)}
              canPost={canPost}
            />
          </>
        )}
      </div>
    </div>
  );
}

