// ── Org chart constants ────────────────────────────────────────────────────────
const MEMBER_TITLES = {
  head_pmo:    "Head PMO",
  manager_pmo: "Manager PMO",
  deputy_pmo:  "Deputy Manager PMO",
  exec_pmo:    "Executive PMO",
  po1:         "Projects Officer",
  po2:         "Projects Officer",
};

// Exact pixel positions for SVG connecting lines + card placement
// Container: 660×500. All coordinates are centers of cards or line endpoints.
const ORG_LAYOUT = {
  head_pmo:    { left:230, top:20,  w:200, h:130, cx:330, cy_bot:150 },
  manager_pmo: { left:90,  top:210, w:160, h:110, cx:170, cy_top:210, cy_bot:320 },
  deputy_pmo:  { left:370, top:210, w:160, h:110, cx:450, cy_top:210 },
  exec_pmo:    { left:20,  top:385, w:140, h:95,  cx:90,  cy_top:385 },
  po1:         { left:170, top:385, w:140, h:95,  cx:240, cy_top:385 },
  po2:         { left:320, top:385, w:140, h:95,  cx:390, cy_top:385 },
};

// ── Module-level sub-components (stable refs = no focus loss) ──────────────────
function OrgCard({ T, roleId, data, isPMO, onEdit }) {
  const [imgErr, setImgErr] = useState(false);
  const L  = ORG_LAYOUT[roleId];
  const title = MEMBER_TITLES[roleId] || roleId;
  const name  = data?.name  || "";
  const desc  = data?.desc  || "";
  const photo = data?.photo || "";
  const init  = name ? name.split(" ").map(w=>w[0]).join("").slice(0,2).toUpperCase() : title.slice(0,2).toUpperCase();
  const isLg  = roleId === "head_pmo";
  const avatarSz = isLg ? 60 : 44;
  return (
    <div style={{
      position:"absolute", left:L.left, top:L.top, width:L.w,
      background:T.card, border:`1px solid ${T.border}`, borderRadius:11,
      padding:isLg?"16px 14px 12px":"12px 12px 10px", textAlign:"center",
      boxShadow:`0 ${isLg?4:2}px ${isLg?14:8}px rgba(0,0,0,0.12)`,
    }}>
      {/* Photo / avatar */}
      {photo && !imgErr ? (
        <img src={photo} alt={name} onError={()=>setImgErr(true)}
          style={{ width:avatarSz, height:avatarSz, borderRadius:"50%", objectFit:"cover", margin:`0 auto ${isLg?10:7}px`, display:"block" }} />
      ) : (
        <div style={{ width:avatarSz, height:avatarSz, borderRadius:"50%", margin:`0 auto ${isLg?10:7}px`,
          background:`linear-gradient(135deg,${NAVY},#1060A0)`,
          display:"flex", alignItems:"center", justifyContent:"center",
          fontSize:isLg?18:13, fontWeight:700, color:"#fff",
        }}>{init}</div>
      )}
      <div style={{ fontSize:9, fontWeight:700, color:GOLD, textTransform:"uppercase", letterSpacing:1.4, marginBottom:3 }}>{title}</div>
      <div style={{ fontSize:isLg?13:11.5, fontWeight:700, color:T.text, lineHeight:1.25, marginBottom:desc?4:0 }}>
        {name || <span style={{ color:T.dim, fontStyle:"italic", fontWeight:400, fontSize:10 }}>{isPMO?"Click ✏ to add":"—"}</span>}
      </div>
      {desc && <div style={{ fontSize:9.5, color:T.muted, lineHeight:1.4, overflow:"hidden", display:"-webkit-box", WebkitLineClamp:3, WebkitBoxOrient:"vertical" }}>{desc}</div>}
      {isPMO && (
        <button onClick={onEdit} style={{ position:"absolute", top:5, right:5, background:"none", border:`1px solid ${T.border}`, borderRadius:4, width:20, height:20, cursor:"pointer", fontSize:10, display:"flex", alignItems:"center", justifyContent:"center", color:T.muted }}>✏</button>
      )}
    </div>
  );
}

// OrgCardInner — content-only card (parent wrapper handles absolute positioning)
